INSERT INTO `textos` (`id`, `tipo`, `modo`, `titulo`, `conteudo`, `peso`, `data_publicacao`) VALUES
(1, 'poesia', 'aleatorio', 'Se não existe o sagrado', 'Se não existe o sagrado\nO lobo não corre na tempestade, uivando no vento\n\nSe não existe o sagrado\nO céu não tinge os olhares intrigados na noite\n\nSe não existe o sagrado\nO luar não se derrama pelos trigais amarelos\n\nSe não existe o sagrado\nO silêncio nada inspira aos amantes\n\nSe não existe o sagrado\nNão há o frescor do orvalho sobre o cansaço da ciência\n\nSe não existe o sagrado\nA fúria do mar não nos deixa introspectivos\n\nSe não existe o sagrado\nO infinito não é misterioso e revela-se a qualquer tolo\n\nSe não existe o sagrado\nNão há o desconhecido\nE sem ele nada é\nPorque nada pode tornar-se.', 1, '2026-05-30 16:04:26'),
(2, 'poesia', 'aleatorio', 'Sábado à noite', 'Encontros\nLabiais....\n\nDesencontros\nNormais...\n\nOlhares\nLetais...\n\nSeduções\nGestuais...\n\nCarícias...\nAnimais...\n\nIlusões\nGeniais...\n\nGestos\nSinais...\n\nSentidos\nIrracionais...\n\nMomentos\nRadicais...\n\nLábios\nCarnais...\n\nMemórias\nSensuais...\n\nPlanos\nMarginais...\n\nNoites\nAncestrais...', 2, '2026-05-30 16:04:26'),
(3, 'poesia', 'aleatorio', 'A noite da consciência', 'Um cão selvagem corre por minhas veias\nNão é daqui, mas de outros tempos\nVaga pelos milênios perdidos em meus sonhos\nSalta tantas montanhas\nE cruza tantos desertos\nQuanto a lua pode ver de seu silêncio\n\nNos uivos desse cão não há história nenhuma\nHá somente a vastidão, o espaço e o universo que se conhece por si mesmo\nMudo na noite intensa, sem que a consciência tenha explodido a admirá-lo\n\nO cão selvagem nunca descansa,\nE sente o suor frio em sua pele quente\nE luta ferozmente pelo prazer de correr o mundo inteiro selvagem\nSe é desafiado a sobreviver,\nSe é ameaçado por outros ferozes animais\n\nNão há sonho que ele já não tenha vivido\nNão há um parto da natureza que se esconda dele\nNão há luta que não tenha travado\nNão há território inabitado que ele não conheça\nNão há noite que se livre de seu ganido distante\nNão há ar glacial ou equatorial que não tenha sido respirado por seus pulmões ofegantes\n\nUm cão selvagem corre por minhas veias \nEle é de outros tempos\nE não é violento nem maldoso\nPorque em seu tempo não existe a maldade\nNão é caridoso ou subserviente\nPorque em seu tempo só há seres selvagens como ele\n\nNinguém sabe de onde ele veio\nOu se um dia irá de minha profundidade\nEle sempre existiu e nunca morrerá\nAdmirará a lua virgem de qualquer olhar humano, de cima de um monte sagrado\nConhecerá os raios de sol que nunca tocaram um só pensamento\nUivará forte procurando sua companheira selvagem, porque é sua natureza\n\nNão existem dúvidas nem certezas por seus caminhos\nSó existe a terra virgem e aberta a seus passos\nE a liberdade de não haver nenhum caminho\n\nCerta vez ele viu uma fogueira em volta da qual homens das pedras cismavam\nDespreocupados do ontem e do amanhã\nEntreolhavam-se tão quietos quanto pode ser a pureza e a inocência da natureza\nE o cão selvagem correu em direção a eles\nE ao tocá-los, mergulhou na história humana,\nE nada lhe foi olvidado\nE quase cego pelo que viu\nE ansioso, ofegante, extenuado\nEncontrou outra fogueira e outros homens ao redor dela\nCorreu desesperadamente ao seu encontro\nE pode retornar a seu tempo\nOnde não há tempo nenhum\nE salta de uma montanha a outra, forte\nE cruza os desertos,\nE é tão livre porque desconhece o que seja uma prisão\n\nNuma feita experimentou o descanso\nDormindo num campo de mato orvalhado pela madrugada\n\nFoi ai a única vez que eu quase o vi\nQuando perdi a consciência de mim e de tudo ao redor\nMas me transformei nele e pude vagar pela noite desconhecida\nE percorri as veias de um homem sem ser um homem\nVi explosões de pensamentos e memórias no horizonte\nSem saber o que significasse isso\nE corri livremente sem nenhum cansaço.\n\n\n\n\n\nÁs vezes quase o vejo.', 3, '2026-05-30 16:04:26'),
(4, 'poesia', 'aleatorio', 'Aos jovens perdidos e guerreiros cansados', 'Aos soldados perdidos de longe de seus lares\nCravados à espinha pás e pedras\nAo impetuoso atirados\nSem fogueira que os eleve\n\nPor dentro e por fora tímidos\nSentados ao chão imersos\nComo tintas à tela árida\nDe um só traço indefinido desenhados\nAo tear com fios de sangue\nÀ navalha presa nas nuvens\nNo horizonte vermelho crava-se o azul\nEm seus olhos penetrados\n\nCalemos nossa voz e nosso julgamento\nOremos aos seus pais e suas mães\nAbrindo o peito distantes\nA esses jovens atirados ao mundo\n\nBenzamos a eles suas vontades\nDe voltar para casa e beijar\nSeus pequenos irmãos inocentes.', 4, '2026-05-30 16:04:26'),
(5, 'poesia', 'aleatorio', 'Champagne à memória', 'Ainda vamos rir juntos de tudo isso... baby\nDos faróis bêbados de minhas mãos inseguras nos teus peitos\nDo meu desespero Fred Astaire sapateando no palco\nDo lago sereno de teu olhar\n\nDas palavras saltando de paraquedas de nossas bocas\nDe sonhar um filho, baby\nDa violência de tua beleza\nDe estar perdido no caos de seus braços\n\nDe nossas pernas embaraçadas\nDo ver-te partir no horizonte enquanto eu agonizava tua despedida\n\nAinda vamos rir juntos de tudo isso, baby...\nPensando no nada, como os inocentes nas calçadas...', 5, '2026-05-30 16:04:26'),
(6, 'poesia', 'aleatorio', 'Sujaram as águas do Ipiranga', 'Cá entre nós\nSujaram as águas do Ipiranga...\nPoluíram suas margens plácidas \nAs fábricas esquizofrênicas e irracionais... \n\nA pátria amada mãe gentil\nNão é dos filhos que pariu\nÉ de poucos\nA pátria mãe gentil\nDa puta que pariu\n\nE diga ao verde-louro dessa flâmula\nQue somos negros, que somos mulatos\nQue somos reais\nQue somos o povo mestiço, com orgulho...\n\nO país é varonil, impávido colosso\nE o povo, rói o osso\n\nDe um povo heroico o brado retumbante\nÉ só um grito ideal e belo, nas lajes pobres de concreto\n\nDiversas fomes, a fome é real\nA desigualdade é real\nA chantagem do capital é real....\n\nNo céu da pátria neste instante há mentiras\n\nTeu seio de liberdade deixou-se conquistar pelo capital transnacional....\n\nE o sol da liberdade? Em raios fúlgidos?\nQual nada... somos escravos da incompetência, escravos da corrupção\nSomos escravos do absurdo\n\nIdolatradas ilusões....\nIdolatrados pães e circos e sexos....\n\nDeitado eternamente em berço esplendido\nBerço esplendido e estéril...\n\nDos filhos deste solo és mãe gentil\nDe filhos submissos\nSobre tuas asas de caos do capital feroz e impiedoso...\nUm golpe no meu peito nacional\n\nSalve salve! A poucocracia\nA prostitutocracia infantil absurda\nSalve salve! A luxocracia brilhando nas retinas de um povo carente\nSalve salve! A absurdocracia\nSalve salve! A mão de ferro maquinal em rostos bonitos e televisivos...\n \nTerra amada, lembra de meus pés descalços?\nTerra amada, eu sei teu gosto e teu cheiro até hoje......\nTerra adorada\nOnde resplandece a imagem do cruzeiro?\nEm quartos luxuosos, ou em barracos?\nOnde resplandece a imagem do cruzeiro?\nNos olhos sedentos de teu povo?\n \nPoluíram as margens do Ipiranga\nEnlouqueceu a pátria mãe gentil\nEmudeceu o brado retumbante\nSecaram os seios da liberdade\nA imagem do cruzeiro não resplandece, se esquece\nImpávido colosso esquelético\nTeu formoso céu risonho e límpido, e poluído, e distante...', 6, '2026-05-30 16:04:26'),
(7, 'poesia', 'fixo', '***', 'Não estou aqui, não estou em lugar nenhum\nNão sou agora, não estou em tempo algum\nEu sou apenas a memória que construí de mim mesmo.', 2, '2026-05-30 16:04:26'),
(8, 'poesia', 'fixo', 'Língua', 'O artigo\né fiel amigo do substantivo\n\no pronome\né assim com o verbo\n\nadjetivo\nalma\n\no tal do adjunto\neu nunca entendi bem\nmas tem lá o seu sentido\n\no numeral me acumula\nquantos beijos já te dei\n\nlembra da velha casamenteira preposição\nque o diabo foi vírgula da nossa separação\ne depois somente mais algumas palavras\nponto final\nfim e recomeço\n\nA língua é do povo\nSó do povo\nmais de ninguém\ne é perfeita\n\nna boca dos humildes ela é ainda mais\nperfeitamente imperfeita\ne o poeta vai lá e erra\nDe propósito!', 2, '2026-05-30 16:04:26'),
(9, 'poesia', 'fixo', 'Para os adolescentes', 'Aos sete anos você tinha pelo menos uma cicatriz de infância\n\nAos dez você já tinha um pequeno amor idealizado, desses de criança\n\nAos treze uma espinha no rosto era o maior de seus problemas\n\nAos quinze, um desejo fervoroso era impossível de inexistir\n \nAos vinte você terá algumas paixões perdidas\n\nAos vinte cinco terá abandonado pelo menos um emprego, terá fracassado em um plano, e se decepcionado com um grande sonho\n\nAos trinta já haverá muitos desejos abandonados\nAos trinta e cinco tentará viver sua juventude novamente, toda em um só dia\n\nAos quarenta já terá provado uma sua qualidade, e conhecerá suas forças e fraquezas, e terá também uma cicatriz nos sentimentos, profunda, muito profunda...\n\nMas aos quarenta é que a mágica acontece: você já terá passado por uma dezena de situações de ridículo, e aceitará sua condição, por entender que não passar por alguns ridículos é impossível.\n\nAos quarenta e cinco abandonará umas manias e adquirirá outras\n\nAos cinquenta perdoará as pequenas irresponsabilidades dos jovens, até as engrandecerá, e terá algum orgulho de seus erros\n- a juventude é impetuosa -\n\nAos cinquenta e cinco, se sobreviver à poluição, ao divórcio, às guerras sem fim, aos sempre mesmos e novos planos econômicos, à irritação com a política, no máximo nesta idade, dará mais atenção às suas necessidades e condição humana, e terá a coragem de admiti-las, dizendo: não e pronto...\n\nAos sessenta seu humor se tornará um pouco mais irritadiço, ou calmo de vez\nPorque o tempo não melhora, nem piora, nem lembra nem esquece, não cobra e não pode ser cobrado\nO tempo só reafirma cada vez mais.....\n\nAos sessenta e cinco sentir-se-á um vencedor por ter sobrevivido a tempestades tropicais, à solidão que às vezes o desolava, aos produtos químicos inconscientes, ao excesso de doces e comida, à decepção com a derrota de seu time, ao eterno jogo humano, ao olhar alheio, ao medo de se expor ao ridículo, e não terá mais medos como dantes\n\nAos setenta, você se lamentará ou poderá rir de tudo isso e de si mesmo\n\nSe houver pelo menos um pouco de inteligência, optará pelo riso, e verá jovens errando no mundo, sentindo ser eles, como se assistisse um filme...', 3, '2026-05-30 16:04:26'),
(10, 'poesia', 'fixo', '***', 'Apague as pálpebras\nDesligue o mundo, baby\n\nFeche a janela do desespero\nBrinque no quintal varrido do inconsciente\nEnlouquece esse tempo\n\nE seremos inocentes de novo...', 4, '2026-05-30 16:04:26'),
(11, 'poesia', 'fixo', '***', 'Não sei o que sou\nNão sei a que venho ou a que vou\nPor isso plagio o pensador\nPorque trago a mesma dor no peito\nE no fundo o mesmo amor.', 5, '2026-05-30 16:04:26'),
(12, 'poesia', 'fixo', '', 'O Brasil não é memória de Portugal\nO Brasil beija de língua Portugal.', 1000, '2026-05-30 16:04:26'),
(13, 'poesia', 'fixo', 'Frenético', 'Beijo suicida\nEspírito da tragédia\nVênus dançante\n\nHoje não sou o que você quer\n\nSou o corpo do escravo\nO gozo do gênio\nFaraó de toalhas pornográficas\nVerbo bombástico\nSemântica semiótica da loucura\nOs nervos do guerreiro no último segundo\n\nNão\nDefinitivamente não sou o que você quer\n\nAmor sem perdão\nUm tiro na noite escura\nÁtomo ínfimo e infinito\nSustento do universo\n\nFogo na galáxia\nNudez dos corpos\nVil metal nos dedos das prostitutas\nBizão forte que calca a lama\n\nNão\nHoje não\nHoje não sou o que você quer\n\nPutas e esquizofrênicos\nSou muito mais eles\ndo que muita coisa que estou vendo!\n\nInsâno\nDeus virado no santo\nMais fogo\nOlhos no nevoeiro\nSilêncio abismante\nTiro no peito\nMedo dos marinheiros\nFuror da fúria\nRisco no céu\nBeijo caótico\nSolidão das noites\n\nAmanhã é outro dia e\nAndarei reto e dócil\n\nMas dentro de mim há tudo isso.', 1, '2026-05-30 16:04:26'),
(14, 'poesia', 'fixo', 'Razão Suficiente', 'Tudo que é\nO é\nPorque há razão suficiente\nTudo que não é\nNão o é\nPor falta de razão suficiente', 50, '2026-05-30 16:04:26'),
(15, 'poesia', 'fixo', '***', 'De manhã eu vivo\nÀ tarde eu sobrevivo\nÀ noite eu me desespero', 60, '2026-05-30 16:04:26'),
(16, 'poesia', 'fixo', 'Ruas', 'Frases\nFases\nFebre\nFezes\n\nFazes\nCelebres\n\nFoices\nCoices\n\nFindo dia\nFim da\nLinha\n\nCozes\nUm vestido\nDe fita\nDe chita\n\nLajes\nCarros\nAlgozes\n\nChores\nLágrimas\nMolhem\nCores\nRuas\nDia\nNum dia\nEm que tudo\nExistia', 10, '2026-05-30 16:04:26'),
(17, 'poesia', 'fixo', 'Palavras', 'Palavras\n\nPalavras são perigosas\nPalavras esclarecem, palavras enfurecem\n\nPalavras causam a paz\nPalavras causam a guerra\n\nPalavras\nEmudecem\n\nPalavras\n\nPalavras são poderosas\n\nPalavras curam\nE palavras causam a dor\n\nDe onde vem a palavra?', 50, '2026-05-30 16:04:26'),
(18, 'frases', 'aleatorio', '', 'A vida pode ser tudo, menos o ideal.', 1, '2026-05-30 16:04:26'),
(19, 'frases', 'aleatorio', '', 'A experiência é o carrasco da inocência.', 2, '2026-05-30 16:04:26'),
(20, 'frases', 'aleatorio', '', 'O segredo? Todos são carentes.', 3, '2026-05-30 16:04:26'),
(21, 'frases', 'aleatorio', '', 'A propriedade privada é a grande fé do homem.', 5, '2026-05-30 16:04:26'),
(22, 'frases', 'aleatorio', '', 'Será?', 10, '2026-05-30 16:04:26'),
(23, 'frases', 'aleatorio', '', 'O que é o socialismo? O socialismo é um ideal. \nO que é o capitalismo? O capitalismo é o real. \nComo acabar com um ideal? E como acabar com o real?\nAmbos indestrutíveis.', 20, '2026-05-30 16:04:26'),
(24, 'frases', 'aleatorio', '', 'O inconsciente é o que está embaixo do nariz e não se vê.', 8, '2026-05-30 16:04:26'),
(25, 'frases', 'fixo', '', 'Consciência: como o universo pôde se olhar no espelho?\nComo pode haver um fora e um dentro que são a mesma coisa?\nEspelho.\nA consciência é o universo no espelho.', 1, '2026-05-30 16:04:26'),
(26, 'frases', 'fixo', '', 'Se precisamos de lei é porque no fundo não há nenhuma lei.', 2, '2026-05-30 16:04:26'),
(27, 'frases', 'fixo', '', 'O tempo é a poesia de Deus.', 3, '2026-05-30 16:04:26'),
(28, 'frases', 'fixo', '', 'Eu sou um literato. Tudo que eu espero é a traição.', 4, '2026-05-30 16:04:26'),
(29, 'frases', 'fixo', '', 'Não precisava tanta malícia no mundo, no olhar já há o suficiente.', 5, '2026-05-30 16:04:26'),
(30, 'frases', 'fixo', '', 'O universo tem dois lados: o rico e o pobre.', 6, '2026-05-30 16:04:26'),
(31, 'frases', 'fixo', '', 'A própria personalidade: o lugar mais provável onde se perder e o único possível onde se encontrar,', 3, '2026-05-30 16:04:26'),
(32, 'frases', 'fixo', '', 'Eu posso não ser muito, mas pelo menos eu sou um pouquinho.', 1050, '2026-05-30 16:04:26'),
(33, 'frases', 'fixo', '', 'A razão é o maior consolo.', 0, '2026-05-30 16:04:26'),
(34, 'frases', 'fixo', '', 'Quanto menor, mais cruel.', 901, '2026-05-30 16:04:26'),
(35, 'frases', 'fixo', '', 'Ideologia é a mentira pequena que encobre a grande verdade.', 100, '2026-05-30 16:04:26'),
(36, 'frases', 'fixo', '', 'Qual é a fé de Deus? Teria Deus fé no homem?', 16, '2026-05-30 16:04:26'),
(37, 'frases', 'fixo', '', 'A razão pede licença. A arte entra com os dois pés na peito.', 20, '2026-05-30 16:04:26'),
(38, 'frases', 'fixo', '', 'Não foi por diferença cultural. Foi por dinheiro mesmo.', 35, '2026-05-30 16:04:26'),
(39, 'frases', 'fixo', '', 'Eva seduziu Adão com a maçã... do rosto.', 90, '2026-05-30 16:04:26'),
(40, 'frases', 'fixo', '', 'O que a gente pensa nunca é.', 70, '2026-05-30 16:04:26'),
(41, 'frases', 'fixo', '', 'Razão é solidão. A maioria vive o espírito prático.', 8, '2026-05-30 16:04:26'),
(42, 'frases', 'fixo', '', 'Se queres contar uma mentira em que todos acreditem, diz apenas: “é uma tradição”.', 15, '2026-05-30 16:04:26'),
(43, 'frases', 'fixo', '', 'Metade da existência é comida e teto...', 9, '2026-05-30 16:04:26'),
(44, 'frases', 'fixo', '', 'Pros sentimentos há três caminhos: vivê-los, tratá-los ou esquecê-los...', 22, '2026-05-30 16:04:26'),
(45, 'frases', 'fixo', '', 'O sexo tinha mais graça quando era proibido.', 25, '2026-05-30 16:04:26'),
(46, 'frases', 'fixo', '', '\"O que é\" sempre leva a um regresso infinito ou aos limites do conhecimento. Talvez o homem seja mais adaptado ao \"como\".', 13, '2026-05-30 16:04:26'),
(47, 'frases', 'fixo', '', 'Só existe amor entre iguais.', 5, '2026-05-30 16:04:26'),
(48, 'frases', 'fixo', 'Dos sentimentos', 'Os sentimentos são um caminhão carregado e sem freio na descida.', 35, '2026-05-30 16:04:26'),
(49, 'frases', 'fixo', '', 'Os animais são inocentes.', 31, '2026-05-30 16:04:26'),
(50, 'frases', 'fixo', '', 'Consciência: conhecimento ou coragem?', 16, '2026-05-30 16:04:26'),
(51, 'frases', 'fixo', '', 'A vida inteira eu convivi comigo. Eu estou de saco cheio de mim.', 1049, '2026-05-30 16:04:26'),
(52, 'frases', 'fixo', '', 'A propriedade privada é a fé do homem, e o mercado sua religião.', 500, '2026-05-30 16:04:26'),
(53, 'frases', 'fixo', '', 'Eu sempre reservo um espaço para os meus erros. Eu me conheço não é de hoje.', 400, '2026-05-30 16:04:26'),
(54, 'frases', 'fixo', '', 'Do ponto de vista do \"O que é\", no limite, não sabemos nada, ou muito pouco. Talvez sejamos mais adaptados ao \"como\".', 401, '2026-05-30 16:04:26'),
(55, 'frases', 'fixo', '', 'A arte é o único descanso o homem.', 5, '2026-05-30 16:04:26'),
(56, 'frases', 'fixo', '', 'O que ameaça a vida humana é a opinião.', 300, '2026-05-30 16:04:26'),
(57, 'frases', 'fixo', '', 'O que ameaça a vida humana é a opinião: a democracia não é fruto da opinião, mas da razão e do raciocínio. Estamos num jogo com suas regras, chamado democracia, onde a opinião é um dos fatores e direitos, dentro dos seus limites. Afinal, a torcida também participa do jogo e seria uma maldade calá-la. O calor da torcida encanta e anima, porém, a competência sempre poderá contrariar uma torcida que emitirá sua opinião, mas não mudará o resultado dessa peleja chamada realidade.', 301, '2026-05-30 16:04:26'),
(58, 'frases', 'fixo', '', 'A justiça tem numa os ideais e na outra um porrete.', 200, '2026-05-30 16:04:26'),
(59, 'frases', 'fixo', '', 'O banco é uma instituição onde o o povo fica do lado de fora e o dinheiro trancado do lado de dentro.', 200, '2026-05-30 16:04:26'),
(60, 'frases', 'fixo', 'Solidão', 'Não fossem os amigos, os homens dormiriam com seus inimigos.', 100, '2026-05-30 16:04:26'),
(61, 'frases', 'fixo', '', 'Só confiarei num filósofo que não tenha os dentes.', 200, '2026-05-30 16:04:26'),
(62, 'frases', 'fixo', '', 'A solidão é a pequena coisa maior grande coisa que eu conheci no universo!', 200, '2026-05-30 16:04:26'),
(63, 'frases', 'fixo', '', 'A coisa só acontece quando há razão suficiente para que ela aconteça.', 40, '2026-05-30 16:04:26'),
(64, 'frases', 'fixo', '', 'O que dizer aos animais? Cuidado com os homens.', 100, '2026-05-30 16:04:26'),
(65, 'frases', 'fixo', '', 'Um cético pode não saber o que o mundo é, mas pode denunciar o que ele não é, e isso já é um grande trabalho.', 70, '2026-05-30 16:04:26'),
(66, 'frases', 'fixo', '', 'O menino nunca abandona o homem.', 0, '2026-05-30 16:04:26'),
(67, 'frases', 'fixo', 'Razão Suficiente', 'Tudo que é\nO é\nPorque há razão suficiente\nTudo que não é\nNão o é\nPor falta de razão suficiente\n\nO que deveria ser, mas sinda não é \nBusca razão suficiente \n\nO que atingiu razão suficiente \nNão precisa repetir-se ou ser novamente \n\nOs ideais atingiram razão suficiente \nApenas novos ideais precisam ser atingidos \nPorque buscam razão suficiente \n\nNão se sabe, se a realidade procura os ideais \nOu é a razão que procura os ideais\nSeja o que for, o faz por necessidade \nNecessidade de razão suficiente \n\nE talvez isso explique ainda mais\nUma vez criança, não é necessário mais dela\nE a juventude, a madureza, a velhice, a vida\nTeimam em abandonar-se, tudo fica para trás \nE não há a necessidade de repetir-se\nPorque foi atingida a razão suficiente \n\nTalvez por isso \nA vida marcha para a morte\nE o nada marche para a vida\nPois biscam atingir algo', 16, '2026-05-30 16:04:26'),
(68, 'frases', 'fixo', '', 'Só existe uma propriedade realmente coletiva no mundo: a da verdade. Todos se dizem dono dela.', 22, '2026-05-30 16:04:26'),
